        for y in range(self.grid.height):
            for x in range(self.grid.width - 2):
                color = self.grid.get_cell(x, y).color
                if color is not None and \
                   self.grid.get_cell(x + 1, y).color == color and \
                   self.grid.get_cell(x + 2, y).color == color:
                    match = [(x, y), (x + 1, y), (x + 2, y)]
                    i = 3
                    while x + i < self.grid.width and self.grid.get_cell(x + i, y).color == color:
