SCREEN_HEIGHT = GRID_HEIGHT * BLOCK_SIZE
GRID_LINE_COLOR = (50, 50, 50)
EMPTY_COLOR = (30, 30, 30)
SPAWN_X = GRID_WIDTH // 2 - 2
SPAWN_Y = 0
PREVIEW_POS = (GRID_WIDTH * BLOCK_SIZE + 20, 50)

LINE_ANIM_FRAMES = 30
MATCH_ANIM_FRAMES = 20

class GameState(Enum):
    ACTIVE = 0
    PAUSED = 1
    GAME_OVER = 2

class TetrisJeweled:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Tetris Jeweled")
        self.clock = pygame.time.Clock()
        self.grid = Grid()
        self.current = self.new_tetromino()
        self.next_piece = self.new_tetromino()
        self.x = SPAWN_X
        self.y = SPAWN_Y
        self.state = GameState.ACTIVE
        self.score = 0
        self.drop_speed = 500
        self.last_drop = pygame.time.get_ticks()
        # animation & clearing
        self.animation_timer = 0
        self.animation_type = None  # 'line' or 'match'
        self.cleared_lines = []
        self.match_positions = set()
        self.chain = 1
        self.spawn_pending = False

    def new_tetromino(self):
        return Tetromino(random.choice(list(BASE_SHAPES.keys())))

    def run(self):
        running = True
        while running:
            dt = self.clock.tick(60)
            for evt in pygame.event.get():
                if evt.type == pygame.QUIT:
                    running = False
                elif evt.type == pygame.KEYDOWN:
                    if evt.key == pygame.K_p:
                        if self.state == GameState.ACTIVE:
                            self.state = GameState.PAUSED
                        elif self.state == GameState.PAUSED:
                            self.state = GameState.ACTIVE
                    elif (self.state == GameState.ACTIVE and self.animation_timer == 0):
                        if evt.key == pygame.K_LEFT:
                            self.move(-1,0)
                        elif evt.key == pygame.K_RIGHT:
                            self.move(1,0)
                        elif evt.key == pygame.K_DOWN:
                            self.move(0,1)
                        elif evt.key == pygame.K_UP:
                            self.rotate()
                        elif evt.key == pygame.K_SPACE:
                            self.hard_drop()
            if self.state == GameState.ACTIVE:
                self.update(dt)
            self.render()
            pygame.display.flip()
        pygame.quit()

    def update(self, dt):
        if self.animation_timer > 0:
            self.animation_timer -= 1
            if self.animation_timer == 0:
                if self.animation_type == 'line':
                    # after line, look for matches
                    matches = self.detect_matches()
                    if matches:
                        self.match_positions = matches
                        self.animation_type = 'match'
                        self.animation_timer = MATCH_ANIM_FRAMES
                        return
                elif self.animation_type == 'match':
                    # clear matched gems
                    self.clear_matches()
                    # collapse and score done in clear_matches
                    # look for next matches
                    matches = self.detect_matches()
                    if matches:
                        self.chain += 1
                        self.match_positions = matches
                        self.animation_type = 'match'
                        self.animation_timer = MATCH_ANIM_FRAMES
                        return
                # end of all clears or no clears
                self.animation_type = None
                self.cleared_lines.clear()
                self.match_positions.clear()
                self.chain = 1
                if self.spawn_pending:
                    self.finish_spawn()
            return

        now = pygame.time.get_ticks()
        if now - self.last_drop >= self.drop_speed:
            self.move(0,1)
            self.last_drop = now

    def move(self, dx, dy):
        nx, ny = self.x+dx, self.y+dy
        if self.is_valid(nx,ny,self.current):
            self.x, self.y = nx, ny
        elif dy != 0:
            self.lock()

    def rotate(self):
        old = self.current.rotation_index
        self.current.rotate()
        if not self.is_valid(self.x,self.y,self.current):
            # revert
            self.current.rotation_index = old
            self.current.blocks = list(self.current.rotations[old])

    def hard_drop(self):
        while self.is_valid(self.x,self.y+1,self.current):
            self.y += 1
        self.lock()

    def is_valid(self, x, y, tet):
        for bx,by in tet.get_blocks(x,y):
            if not self.grid.is_inside(bx,by):
                return False
            if self.grid.get_cell(bx,by).state == CellState.FILLED:
                return False
        return True

    def lock(self):
        for bx,by in self.current.get_blocks(self.x,self.y):
            self.grid.set_cell(bx,by,CellState.FILLED,self.current.color)
        self.spawn_pending = True
        # try line clear
        lines = [y for y in range(self.grid.height)
                 if all(self.grid.get_cell(x,y).state==CellState.FILLED
                        for x in range(self.grid.width))]
        if lines:
            self.cleared_lines = lines
            # remove lines
            for y in sorted(lines):
                for x in range(self.grid.width):
                    self.grid.set_cell(x,y,CellState.EMPTY,None)
                for yy in range(y-1,-1,-1):
                    for x in range(self.grid.width):
                        c = self.grid.get_cell(x,yy)
                        self.grid.set_cell(x,yy+1,c.state,c.color)
                        self.grid.set_cell(x,yy,CellState.EMPTY,None)
            self.score += {1:100,2:300,3:500,4:800}.get(len(lines),len(lines)*100)
            self.animation_type = 'line'
            self.animation_timer = LINE_ANIM_FRAMES
        else:
            # no line, try match
            matches = self.detect_matches()
            if matches:
                self.match_positions = matches
                self.animation_type = 'match'
                self.animation_timer = MATCH_ANIM_FRAMES
            else:
                self.finish_spawn()

    def finish_spawn(self):
        self.current = self.next_piece
        self.next_piece = self.new_tetromino()
        self.x, self.y = SPAWN_X, SPAWN_Y
        self.spawn_pending = False
        if not self.is_valid(self.x,self.y,self.current):
            self.state = GameState.GAME_OVER

    def detect_matches(self):
        visited = [[False]*self.grid.width for _ in range(self.grid.height)]
        matches = set()
        for y in range(self.grid.height):
            for x in range(self.grid.width):
                cell = self.grid.get_cell(x,y)
                if cell.state==CellState.FILLED and not visited[y][x]:
                    color = cell.color
                    stack = [(x,y)]
                    comp = []
                    visited[y][x] = True
                    while stack:
                        cx,cy = stack.pop()
                        comp.append((cx,cy))
                        for dx,dy in ((1,0),(-1,0),(0,1),(0,-1)):
                            nx,ny = cx+dx, cy+dy
                            if (0<=nx<self.grid.width and 0<=ny<self.grid.height
                                and not visited[ny][nx]):
                                nc = self.grid.get_cell(nx,ny)
                                if nc.state==CellState.FILLED and nc.color==color:
                                    visited[ny][nx]=True
                                    stack.append((nx,ny))
                    if len(comp)>=3:
                        matches.update(comp)
        return matches

    def clear_matches(self):
        # remove matched cells
        for x,y in self.match_positions:
            self.grid.set_cell(x,y,CellState.EMPTY,None)
        # collapse each column
        for x in range(self.grid.width):
            stack = []
            for y in range(self.grid.height):
                c = self.grid.get_cell(x,y)
                if c.state==CellState.FILLED:
                    stack.append(c.color)
            for y in range(self.grid.height-1,-1,-1):
                if stack:
                    color = stack.pop()
                    self.grid.set_cell(x,y,CellState.FILLED,color)
                else:
                    self.grid.set_cell(x,y,CellState.EMPTY,None)
        # score
        self.score += len(self.match_positions) * 50 * self.chain

    def render(self):
        self.screen.fill((0,0,0))
        self.draw_grid()
        if self.state!=GameState.GAME_OVER and self.animation_timer==0:
            self.draw_tetromino()
        self.draw_next()
        self.draw_score()
        if self.state==GameState.PAUSED:
            self.draw_overlay("Paused")
        elif self.state==GameState.GAME_OVER:
            self.draw_overlay("Game Over", final=True)

    def draw_grid(self):
        for y in range(self.grid.height):
            for x in range(self.grid.width):
                cell = self.grid.get_cell(x,y)
                rect = pygame.Rect(x*BLOCK_SIZE, y*BLOCK_SIZE,
                                   BLOCK_SIZE, BLOCK_SIZE)
                color = EMPTY_COLOR
                if self.animation_timer>0:
                    if self.animation_type=='line' and y in self.cleared_lines:
                        color = (255,255,255) if (self.animation_timer%2==0) else EMPTY_COLOR
                    elif self.animation_type=='match' and (x,y) in self.match_positions:
                        color = (255,255,255) if (self.animation_timer%2==0) else EMPTY_COLOR
                    else:
                        if cell.state==CellState.FILLED:
                            color = cell.color
                else:
                    if cell.state==CellState.FILLED:
                        color = cell.color
                pygame.draw.rect(self.screen, color, rect)
                pygame.draw.rect(self.screen, GRID_LINE_COLOR, rect, 1)

    def draw_tetromino(self):
        for bx,by in self.current.get_blocks(self.x,self.y):
            rect = pygame.Rect(bx*BLOCK_SIZE, by*BLOCK_SIZE,
                               BLOCK_SIZE, BLOCK_SIZE)
            pygame.draw.rect(self.screen, self.current.color, rect)
            pygame.draw.rect(self.screen, GRID_LINE_COLOR, rect, 1)

    def draw_next(self):
        font = pygame.font.Font(None,30)
        label = font.render("Next:", True, (255,255,255))
        self.screen.blit(label, (PREVIEW_POS[0], PREVIEW_POS[1]-30))
        for bx,by in self.next_piece.get_blocks(0,0):
            px = PREVIEW_POS[0] + bx*BLOCK_SIZE
            py = PREVIEW_POS[1] + by*BLOCK_SIZE
            rect = pygame.Rect(px,py,BLOCK_SIZE,BLOCK_SIZE)
            pygame.draw.rect(self.screen, self.next_piece.color, rect)
            pygame.draw.rect(self.screen, GRID_LINE_COLOR, rect,1)

    def draw_score(self):
        font = pygame.font.Font(None,36)
        text = font.render(f"Score: {self.score}", True, (255,255,255))
        self.screen.blit(text, (PREVIEW_POS[0], PREVIEW_POS[1]+150))

    def draw_overlay(self, text, final=False):
        ov = pygame.Surface((SCREEN_WIDTH,SCREEN_HEIGHT), pygame.SRCALPHA)
        ov.fill((0,0,0,180))
        self.screen.blit(ov,(0,0))
        font = pygame.font.Font(None,72)
        lbl = font.render(text, True, (255,255,255))
        rect = lbl.get_rect(center=(SCREEN_WIDTH//2,SCREEN_HEIGHT//2- (60 if final else 0)))
        self.screen.blit(lbl,rect)
        if final:
            sub = pygame.font.Font(None,48).render(f"Final Score: {self.score}", True, (255,255,255))
            r2 = sub.get_rect(center=(SCREEN_WIDTH//2,SCREEN_HEIGHT//2+60))
            self.screen.blit(sub,r2)

if __name__ == '__main__':
    game = TetrisJeweled()
    game.run()
